import React, { useEffect, useState, useCallback, useRef, forwardRef, useImperativeHandle } from "react";
import { Link } from "react-router-dom";

// components
import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

// TextRotate Component - مطابق لوظيفة الكود الثاني
const TextRotate = forwardRef(({
  texts,
  rotationInterval = 2000,
  auto = true,
  loop = true,
  onNext,
  className = "",
  splitBy = "characters"
}, ref) => {
  const [currentTextIndex, setCurrentTextIndex] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);

  // Helper function to split text into characters (supports emojis)
  const splitIntoCharacters = (text) => {
    // Simple split for characters (works for most cases)
    return Array.from(text);
  };

  // Get elements based on splitBy
  const getElements = useCallback((text) => {
    if (splitBy === "characters") {
      const words = text.split(" ");
      return words.map((word, i) => ({
        characters: splitIntoCharacters(word),
        needsSpace: i !== words.length - 1
      }));
    } else if (splitBy === "words") {
      return text.split(" ").map(word => ({
        characters: [word],
        needsSpace: false
      }));
    } else {
      return text.split(splitBy).map(char => ({
        characters: [char],
        needsSpace: false
      }));
    }
  }, [splitBy]);

  const [elements, setElements] = useState(() => getElements(texts[0]));

  // Update elements when text changes
  useEffect(() => {
    setElements(getElements(texts[currentTextIndex]));
  }, [currentTextIndex, texts, getElements]);

  // Handle index change
  const handleIndexChange = useCallback((newIndex) => {
    setIsAnimating(true);
    setCurrentTextIndex(newIndex);
    onNext?.(newIndex);

    // Reset animation state after transition
    setTimeout(() => setIsAnimating(false), 500);
  }, [onNext]);

  // Navigation functions
  const next = useCallback(() => {
    const nextIndex = currentTextIndex === texts.length - 1
      ? (loop ? 0 : currentTextIndex)
      : currentTextIndex + 1;

    if (nextIndex !== currentTextIndex) {
      handleIndexChange(nextIndex);
    }
  }, [currentTextIndex, texts.length, loop, handleIndexChange]);

  const previous = useCallback(() => {
    const prevIndex = currentTextIndex === 0
      ? (loop ? texts.length - 1 : currentTextIndex)
      : currentTextIndex - 1;

    if (prevIndex !== currentTextIndex) {
      handleIndexChange(prevIndex);
    }
  }, [currentTextIndex, texts.length, loop, handleIndexChange]);

  const jumpTo = useCallback((index) => {
    const validIndex = Math.max(0, Math.min(index, texts.length - 1));
    if (validIndex !== currentTextIndex) {
      handleIndexChange(validIndex);
    }
  }, [texts.length, currentTextIndex, handleIndexChange]);

  const reset = useCallback(() => {
    if (currentTextIndex !== 0) {
      handleIndexChange(0);
    }
  }, [currentTextIndex, handleIndexChange]);

  // Expose ref methods
  useImperativeHandle(ref, () => ({
    next,
    previous,
    jumpTo,
    reset
  }), [next, previous, jumpTo, reset]);

  // Auto rotation
  useEffect(() => {
    if (!auto) return;
    const intervalId = setInterval(next, rotationInterval);
    return () => clearInterval(intervalId);
  }, [next, rotationInterval, auto]);

  // Animation styles
  const getAnimationStyle = (index, total) => {
    const delay = index * 0.05; // Stagger effect
    return {
      animation: isAnimating ? `fadeInUp 0.5s ease-out ${delay}s forwards` : "none",
      opacity: 0,
      transform: "translateY(20px)",
      animationFillMode: "forwards"
    };
  };

  return (
    <div className={`inline-flex flex-wrap whitespace-pre-wrap ${className}`}>
      <span className="sr-only">{texts[currentTextIndex]}</span>

      <div className="flex flex-wrap">
        {elements.map((wordObj, wordIndex) => (
          <span key={wordIndex} className="inline-flex">
            {wordObj.characters.map((char, charIndex) => {
              const totalChars = elements.reduce(
                (sum, word) => sum + word.characters.length, 0
              );
              const globalIndex = elements
                .slice(0, wordIndex)
                .reduce((sum, word) => sum + word.characters.length, 0) + charIndex;

              return (
                <span
                  key={charIndex}
                  style={getAnimationStyle(globalIndex, totalChars)}
                  className="inline-block"
                >
                  {char}
                </span>
              );
            })}
            {wordObj.needsSpace && <span className="whitespace-pre"> </span>}
          </span>
        ))}
      </div>

      <style jsx>{`
        @keyframes fadeInUp {
          from {
            opacity: 0;
            transform: translateY(20px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </div>
  );
});

TextRotate.displayName = "TextRotate";

// Main Landing Component
export default function Landing() {
  // ✅ النصوص باللغات
  const texts = [
    "Hello",
    "Bonjour",
    "Ciao",
    "Hola",
    "こんにちは",
    "你好",
    "안녕하세요",
    "नमस्ते",
    "مرحبا"
  ];

  const textRotateRef = useRef();

  // Optional: Example of how to use ref methods
  useEffect(() => {
    // You can call methods like:
    // textRotateRef.current?.next();
    // textRotateRef.current?.previous();
    // textRotateRef.current?.jumpTo(3);
    // textRotateRef.current?.reset();
  }, []);

  return (
    <>
      <Navbar transparent />
      <main>
        <div className="relative pt-16 pb-32 flex content-center items-center justify-center min-h-screen">
          <div
            className="absolute top-0 w-full h-full bg-center bg-cover"
            style={{
              backgroundImage:
                "url('https://t4.ftcdn.net/jpg/09/09/79/85/360_F_909798513_DhTQUUB8Sexbj5rBgsz5qwkarSwvQ3mA.jpg')",
            }}
          >
            {/* Optional overlay for better text readability */}
            <div className="absolute inset-0 bg-black bg-opacity-40"></div>
          </div>

          <div className="container relative mx-auto">
            <div className="items-center flex flex-wrap">
              <div className="w-full lg:w-6/12 px-4 ml-auto mr-auto text-center">
                <div className="pr-12">
                  {/* ✅ TextRotate component with same functionality as the second code */}
                  <TextRotate
                    ref={textRotateRef}
                    texts={texts}
                    rotationInterval={2000}
                    auto={true}
                    loop={true}
                    splitBy="characters"
                    className="text-white font-semibold text-5xl"
                    onNext={(index) => console.log("Current index:", index)}
                  />

                  <p className="mt-4 text-lg text-blueGray-200">
                    Welcome to our website
                  </p>

                  {/* Optional: Manual controls example */}
                  <div className="mt-8 flex justify-center gap-4">
                    <button
                      onClick={() => textRotateRef.current?.previous()}
                      className="px-4 py-2 bg-white bg-opacity-20 hover:bg-opacity-30 rounded-lg text-white transition-all"
                    >
                      Previous
                    </button>
                    <button
                      onClick={() => textRotateRef.current?.next()}
                      className="px-4 py-2 bg-white bg-opacity-20 hover:bg-opacity-30 rounded-lg text-white transition-all"
                    >
                      Next
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* باقي الكود كما هو */}
      </main>
      <Footer />
    </>
  );
}
